namespace sv_cf7120e44e0640f094751277a328dde8.Services;

/// <summary>
/// Scoped service that holds all wizard data for a single user's circuit.
/// Components subscribe to OnChange to re-render when state is modified.
/// </summary>
public class WizardState
{
    // Step 1 – Personal Info
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;

    // Step 2 – Experience
    public List<JobEntry> Jobs { get; set; } = [];

    // Step 3 – References
    public List<ReferenceContact> References { get; set; } = [];

    // Track which steps have been completed
    public HashSet<int> CompletedSteps { get; } = [];

    public event Action? OnChange;

    public void NotifyChanged() => OnChange?.Invoke();

    public void MarkStepCompleted(int step)
    {
        CompletedSteps.Add(step);
        OnChange?.Invoke();
    }
}

public class JobEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Years { get; set; } = string.Empty;
}

public class ReferenceContact
{
    public string Name { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
    public string Phone { get; set; } = string.Empty;
}

namespace sv_cf7120e44e0640f094751277a328dde8.Services;

