@rendermode InteractiveServer
@inject NavigationManager Nav
@inject WizardState Wizard
@inject CascadingValueSource<WizardProgress> ProgressSource

<PageTitle>Apply – Personal Info</PageTitle>

<h1>Step 1: Personal Information</h1>

<div class="mb-3">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="Wizard.Name" />
</div>

<div class="mb-3">
    <label class="form-label">Email Address</label>
    <input class="form-control" type="email" @bind="Wizard.Email" />
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    protected override async Task OnInitializedAsync()
    {
        await ProgressSource.NotifyChangedAsync(
            new WizardProgress(1, Wizard.CompletedSteps));
    }

    private async Task Next()
    {
        Wizard.MarkStepCompleted(1);
        await ProgressSource.NotifyChangedAsync(
            new WizardProgress(2, Wizard.CompletedSteps));
        Nav.NavigateTo("/apply/experience");
    }
}

