toolArgs.file_text:
namespace sv_cf7120e44e0640f094751277a328dde8.Services;

/// <summary>
/// Lightweight record cascaded via CascadingValueSource so the static
/// layout can read the current wizard step across the render-mode boundary.
/// </summary>
public record WizardProgress(int CurrentStep, HashSet<int> CompletedSteps);

@page "/apply/personal-info"
@rendermode InteractiveServer
@inject NavigationManager Nav
@inject WizardState Wizard
@inject CascadingValueSource<WizardProgress> ProgressSource

<PageTitle>Apply – Personal Info</PageTitle>

<h1>Step 1: Personal Information</h1>

<div class="mb-3">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="Wizard.Name" />
</div>

<div class="mb-3">
    <label class="form-label">Email Address</label>
    <input class="form-control" type="email" @bind="Wizard.Email" />
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    protected override async Task OnInitializedAsync()
    {
        await ProgressSource.NotifyChangedAsync(
            new WizardProgress(1, Wizard.CompletedSteps));
    }

    private async Task Next()
    {
        Wizard.MarkStepCompleted(1);
        await ProgressSource.NotifyChangedAsync(
            new WizardProgress(2, Wizard.CompletedSteps));
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@inject NavigationManager Nav
@inject WizardState Wizard
@inject CascadingValueSource<WizardProgress> ProgressSource

<PageTitle>Apply – Experience</PageTitle>

<h1>Step 2: Work Experience</h1>

@for (int i = 0; i < Wizard.Jobs.Count; i++)
{
    var index = i;
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <strong>Job @(index + 1)</strong>
            <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveJob(index)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="Wizard.Jobs[index].Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Title</label>
            <input class="form-control" @bind="Wizard.Jobs[index].Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="Wizard.Jobs[index].Years" />
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddJob">+ Add Job</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="Back">&larr; Back</button>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    protected override async Task OnInitializedAsync()
    {
        await ProgressSource.NotifyChangedAsync(
            new WizardProgress(2, Wizard.CompletedSteps));
    }

    private void AddJob() => Wizard.Jobs.Add(new JobEntry());
    private void RemoveJob(int index) => Wizard.Jobs.RemoveAt(index);

    private async Task Next()
    {
        Wizard.MarkStepCompleted(2);
        await ProgressSource.NotifyChangedAsync(
            new WizardProgress(3, Wizard.CompletedSteps));
        Nav.NavigateTo("/apply/references");
    }

    private void Back() => Nav.NavigateTo("/apply/personal-info");
}

@page "/apply/references"
@rendermode InteractiveServer
@inject NavigationManager Nav
@inject WizardState Wizard
@inject CascadingValueSource<WizardProgress> ProgressSource

<PageTitle>Apply – References</PageTitle>

<h1>Step 3: References</h1>

@for (int i = 0; i < Wizard.References.Count; i++)
{
    var index = i;
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <strong>Reference @(index + 1)</strong>
            <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveRef(index)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Name</label>
            <input class="form-control" @bind="Wizard.References[index].Name" />
        </div>
        <div class="mb-2">
            <label class="form-label">Relationship</label>
            <input class="form-control" @bind="Wizard.References[index].Relationship" />
        </div>
        <div class="mb-2">
            <label class="form-label">Phone</label>
            <input class="form-control" @bind="Wizard.References[index].Phone" />
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddRef">+ Add Reference</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="Back">&larr; Back</button>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    protected override async Task OnInitializedAsync()
    {
        await ProgressSource.NotifyChangedAsync(
            new WizardProgress(3, Wizard.CompletedSteps));
    }

    private void AddRef() => Wizard.References.Add(new ReferenceContact());
    private void RemoveRef(int index) => Wizard.References.RemoveAt(index);

    private async Task Next()
    {
        Wizard.MarkStepCompleted(3);
        await ProgressSource.NotifyChangedAsync(
            new WizardProgress(4, Wizard.CompletedSteps));
        Nav.NavigateTo("/apply/review");
    }

    private void Back() => Nav.NavigateTo("/apply/experience");
}

@page "/apply/review"
@rendermode InteractiveServer
@inject WizardState Wizard
@inject CascadingValueSource<WizardProgress> ProgressSource

<PageTitle>Apply – Review</PageTitle>

<h1>Step 4: Review Your Application</h1>

<h4>Personal Information</h4>
<dl class="row">
    <dt class="col-sm-3">Name</dt>
    <dd class="col-sm-9">@Wizard.Name</dd>
    <dt class="col-sm-3">Email</dt>
    <dd class="col-sm-9">@Wizard.Email</dd>
</dl>

<h4>Work Experience</h4>
@if (Wizard.Jobs.Count == 0)
{
    <p class="text-muted">No jobs added.</p>
}
else
{
    <table class="table table-sm">
        <thead>
            <tr><th>Company</th><th>Title</th><th>Years</th></tr>
        </thead>
        <tbody>
            @foreach (var job in Wizard.Jobs)
            {
                <tr><td>@job.Company</td><td>@job.Title</td><td>@job.Years</td></tr>
            }
        </tbody>
    </table>
}

<h4>References</h4>
@if (Wizard.References.Count == 0)
{
    <p class="text-muted">No references added.</p>
}
else
{
    <table class="table table-sm">
        <thead>
            <tr><th>Name</th><th>Relationship</th><th>Phone</th></tr>
        </thead>
        <tbody>
            @foreach (var r in Wizard.References)
            {
                <tr><td>@r.Name</td><td>@r.Relationship</td><td>@r.Phone</td></tr>
            }
        </tbody>
    </table>
}

<div class="d-flex justify-content-between mt-4">
    <a href="/apply/references" class="btn btn-secondary">&larr; Back</a>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@if (submitted)
{
    <div class="alert alert-success mt-3">Application submitted successfully!</div>
}

@code {
    private bool submitted;

    protected override async Task OnInitializedAsync()
    {
        await ProgressSource.NotifyChangedAsync(
            new WizardProgress(4, Wizard.CompletedSteps));
    }

    private void Submit()
    {
        submitted = true;
    }
}

