@* Static component – renders in the layout's static SSR context *@

<nav aria-label="Wizard progress" class="w-100">
    <div class="d-flex align-items-center justify-content-between mb-1">
        <small class="fw-semibold">Step @CurrentStep of @TotalSteps</small>
    </div>
    <div class="d-flex gap-1">
        @for (int i = 1; i <= TotalSteps; i++)
        {
            var step = i;
            var label = StepLabels[step];
            var css = step == CurrentStep ? "bg-primary"
                    : CompletedSteps.Contains(step) ? "bg-success"
                    : "bg-secondary bg-opacity-25";

            <a href="@StepUrls[step]"
               class="flex-fill text-center rounded py-1 text-decoration-none small text-white @css"
               title="@label">
                @label
            </a>
        }
    </div>
</nav>

@code {
    private const int TotalSteps = 4;

    [Parameter, EditorRequired]
    public int CurrentStep { get; set; }

    [Parameter, EditorRequired]
    public HashSet<int> CompletedSteps { get; set; } = [];

    private static readonly Dictionary<int, string> StepLabels = new()
    {
        [1] = "Personal Info",
        [2] = "Experience",
        [3] = "References",
        [4] = "Review"
    };

    private static readonly Dictionary<int, string> StepUrls = new()
    {
        [1] = "/apply/personal-info",
        [2] = "/apply/experience",
        [3] = "/apply/references",
        [4] = "/apply/review"
    };
}

